def max_alternating_subarray_length(nums):
    n = len(nums)
    max_len = -1

    for start in range(n):
        # For alternating pattern, we need at least 2 elements
        # Pattern: s0, s0+1, s0, s0+1, ...
        curr_len = 1
        for i in range(start + 1, n):
            expected_diff = 1 if (i - start) % 2 == 1 else -1
            if nums[i] - nums[i-1] == expected_diff:
                curr_len += 1
                if curr_len >= 2:
                    max_len = max(max_len, curr_len)
            else:
                break

    return max_len
